
'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';

export default function CreateMaintenancePage() {
  const [assetType, setAssetType] = useState('device');
  const [assetId, setAssetId] = useState('');
  const [description, setDescription] = useState('');
  const [status, setStatus] = useState('pending');
  const [devices, setDevices] = useState([]);
  const [rooms, setRooms] = useState([]);
  const [gadgets, setGadgets] = useState([]);
  const router = useRouter();

  useEffect(() => {
    const fetchAssets = async () => {
      const baseUrl = process.env.NEXT_PUBLIC_VERCEL_URL ? `https://${process.env.NEXT_PUBLIC_VERCEL_URL}` : 'http://localhost:3000';
      const [devicesRes, roomsRes, gadgetsRes] = await Promise.all([
        fetch(`${baseUrl}/api/devices`),
        fetch(`${baseUrl}/api/rooms`),
        fetch(`${baseUrl}/api/gadgets`)
      ]);

      if (devicesRes.ok) {
        const data = await devicesRes.json();
        setDevices(data.devices);
      }

      if (roomsRes.ok) {
        const data = await roomsRes.json();
        setRooms(data.rooms);
      }

      if (gadgetsRes.ok) {
        const data = await gadgetsRes.json();
        setGadgets(data.gadgets);
      }
    };
    fetchAssets();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const newMaintenance = {
      assetId,
      assetType,
      description,
      status,
    };

    const baseUrl = process.env.NEXT_PUBLIC_VERCEL_URL ? `https://${process.env.NEXT_PUBLIC_VERCEL_URL}` : 'http://localhost:3000';
    const res = await fetch(`${baseUrl}/api/maintenances`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newMaintenance),
    });

    if (res.ok) {
      router.push('/maintenances');
    }
  };

  return (
    <div className="container mx-auto p-8">
      <h1 className="text-4xl font-bold mb-8">Create Maintenance</h1>
      <form onSubmit={handleSubmit} className="bg-white dark:bg-gray-800 shadow-md rounded-lg p-8">
        <div className="mb-4">
          <label htmlFor="assetType" className="block text-sm font-medium text-gray-700 dark:text-gray-300">Asset Type</label>
          <select
            id="assetType"
            value={assetType}
            onChange={(e) => setAssetType(e.target.value)}
            className="mt-1 block w-full px-3 py-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
            required
          >
            <option value="device">Device</option>
            <option value="room">Room</option>
            <option value="gadget">Gadget</option>
          </select>
        </div>

        <div className="mb-4">
          <label htmlFor="assetId" className="block text-sm font-medium text-gray-700 dark:text-gray-300">Asset</label>
          <select
            id="assetId"
            value={assetId}
            onChange={(e) => setAssetId(e.target.value)}
            className="mt-1 block w-full px-3 py-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
            required
          >
            <option value="">Select a {assetType}</option>
            {assetType === 'device' && devices.map((device: any) => (
              <option key={device._id} value={device._id}>{device.name}</option>
            ))}
            {assetType === 'room' && rooms.map((room: any) => (
              <option key={room._id} value={room._id}>{room.name}</option>
            ))}
            {assetType === 'gadget' && gadgets.map((gadget: any) => (
              <option key={gadget._id} value={gadget._id}>{gadget.name}</option>
            ))}
          </select>
        </div>

        <div className="mb-4">
          <label htmlFor="description" className="block text-sm font-medium text-gray-700 dark:text-gray-300">Description</label>
          <textarea
            id="description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="mt-1 block w-full px-3 py-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
            required
          />
        </div>

        <div className="mb-4">
          <label htmlFor="status" className="block text-sm font-medium text-gray-700 dark:text-gray-300">Status</label>
          <select
            id="status"
            value={status}
            onChange={(e) => setStatus(e.target.value)}
            className="mt-1 block w-full px-3 py-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
          >
            <option value="pending">Pending</option>
            <option value="in-progress">In Progress</option>
            <option value="completed">Completed</option>
          </select>
        </div>

        <div className="flex justify-end">
          <button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded transition">
            Create
          </button>
        </div>
      </form>
    </div>
  );
}
